import { Component, computed, inject } from '@angular/core';
import { Router } from '@angular/router';
import { MatButtonModule } from '@angular/material/button';
import { MatCardModule } from '@angular/material/card';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import {
  FormControl,
  FormsModule,
  ReactiveFormsModule,
  Validators,
} from '@angular/forms';
import { PortAgentFormService } from '../../../components/port-agent-form/port-agent-form.service';
import { LoaderService } from '../../../shared/loader/loader.service';
import { CommonModule } from '@angular/common';
import { ConfirmationDialogComponent } from '../../../components/confirmation-dialog.component';
import { MatDialog } from '@angular/material/dialog';
import { SuccessMessageService } from '../../../components/port-agent-form/pa-form-submit-success-page/succuss-response-shared.component.service';
import { SnackbarService } from '../../../shared/snack-bar/snack-bar.service';

@Component({
  selector: 'app-return-pda',
  standalone: true,
  imports: [
    MatButtonModule,
    MatCardModule,
    FormsModule,
    ReactiveFormsModule,
    MatFormFieldModule,
    MatInputModule, CommonModule
  ],
  templateUrl: './return-pda.component.html',
  styleUrl: './return-pda.component.css',
})
export class ReturnPdaComponent {
  private loader = inject(LoaderService);
  isLoading = computed(() => this.loader.loading());

  constructor(private routes: Router, private portAgentFormService: PortAgentFormService, private router: Router, private dialog: MatDialog, private successMessageService: SuccessMessageService, private snackbar: SnackbarService) { }

  remarkControl = new FormControl('', Validators.required);

  goToBankForm = (): void => {
    this.routes.navigate(['/pdfa/bankForm']);
  };

  returnToMeraki() {
    if (!this.remarkControl.value) {
      this.remarkControl.markAllAsTouched();
      return;
    }

    const dialogRef = this.dialog.open(ConfirmationDialogComponent, {
      data: {
        header: 'Confirm Send',
        text: 'Are you sure you want to return the request?'
      }
    });

    dialogRef.afterClosed().subscribe(result => {
      if (result === true) {
        const dis_seq = sessionStorage.getItem("pa-success-response");
        if (dis_seq) {
          const parser = JSON.parse(dis_seq);
          const data = {
            disbursement_seq: parser.disbursement_seq,
            return_message: this.remarkControl.value,
            return_status: "Y"
          };
          this.loader.show();
          this.portAgentFormService.returnToMeraki(data).subscribe({
            next: (res: any) => {
              this.loader.hide();
              const successMessage = 'Request has been returned. The link is no longer valid.';
              this.successMessageService.setSuccessMessage(successMessage);
              this.router.navigate(['/submit/success']);
            },
            error: (err) => {
              this.loader.hide();
              const errMsg = err?.error?.error || "Something went wrong please try again later.";
              this.snackbar.showError(errMsg);
            }
          });
        }
      }
    });
  }
}
